const leadName = $json.lead_name || '';
const leadEmail = $json.lead_email || '';
const company = $json.company || '';

// Generar link de Calendly con parámetros pre-llenados
const baseUrl = 'https://calendly.com/nataly-riano-msitechnologiesinc/30min';

const params = new URLSearchParams();
if (leadName) params.append('name', leadName);
if (leadEmail) params.append('email', leadEmail);
if (company) params.append('a1', company); // Custom field for company

const calendlyLink = `${baseUrl}?${params.toString()}`;

// Generar mensaje para el lead
let responseMessage = '';

if (leadEmail) {
  responseMessage = `Perfect! I'm generating a calendar link for you. You can schedule directly at: ${calendlyLink}. You'll be meeting with Nataly Riaño, our Key Account Manager. She'll follow up with a confirmation email to ${leadEmail}. Is there anything specific you'd like her to prepare for the meeting?`;
} else {
  responseMessage = `Great! To send you the calendar invite, could you please confirm your email address? Once I have that, I'll send over the meeting link with Nataly Riaño, our Key Account Manager.`;
}

return [{
  json: {
    response: responseMessage,
    calendly_link: calendlyLink,
    lead_name: leadName,
    lead_email: leadEmail,
    company: company,
    meeting_scheduled: leadEmail ? true : false
  }
}];
